import React from 'react';
import './Products.css';
import shirt1 from '../assets/shirt1.webp';
import shirt2 from '../assets/shirt2.jpg';
import pant1 from '../assets/pant1.jpg';
import pant2 from '../assets/pant2.avif';

function Products() {
  // 🔁 Shirt collection
  const shirts = [
    { id: 1, name: "Casual Shirt", price: "₹799", image: shirt1 },
    { id: 2, name: "Formal Shirt", price: "₹999", image: shirt2 },
    { id: 3, name: "Formal Shirt", price: "₹999", image: shirt2 },
    { id: 4, name: "Formal Shirt", price: "₹999", image: shirt2 },
    // more shirts can be added here...
  ];

  // 🔁 Pant collection
  const pants = [
    { id: 1, name: "Denim Jeans", price: "₹1199", image: pant1 },
    { id: 2, name: "Cotton Chinos", price: "₹899", image: pant2 },
    { id: 3, name: "Cotton Chinos", price: "₹899", image: pant2 },
    { id: 4, name: "Cotton Chinos", price: "₹899", image: pant2 },
    // more pants can be added here...
  ];

  return (
    <div className="products-container">
      <h1 className="section-title">👕 Shirts Collection</h1>
      <div className="product-grid">
        {shirts.map((item) => (
          <div key={item.id} className="product-card">
            <img src={item.image} alt={item.name} />
            <h3>{item.name}</h3>
            <p>{item.price}</p>
          </div>
        ))}
      </div>

      <h1 className="section-title">👖 Pants Collection</h1>
      <div className="product-grid">
        {pants.map((item) => (
          <div key={item.id} className="product-card">
            <img src={item.image} alt={item.name} />
            <h3>{item.name}</h3>
            <p>{item.price}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Products;
